import hashlib, time

class RAGIndexSyncWorker:
    # Consumes MDM change events and keeps the vector index consistent

    def __init__(self, vector_client, embed_fn, consistency_checker):
        self.vector = vector_client
        self.embed = embed_fn
        self.checker = consistency_checker

    def handle_event(self, job: IndexSyncJob) -> bool:
        try:
            if job.should_delete_vector():
                return self._handle_delete(job)
            elif job.event.affects_rag_content():
                return self._handle_upsert(job)
            else:
                # Non-content fields changed; skip re-embed
                return self._handle_metadata_only(job)
        except Exception as exc:
            job.attempts += 1
            job.status = 'failed' if job.attempts >= job.max_retries else 'pending'
            self._log_failure(job, exc)
            return False

    def _handle_delete(self, job: IndexSyncJob) -> bool:
        self.vector.delete(filter={'entity_id': job.event.entity_id})
        return True

    def _handle_upsert(self, job: IndexSyncJob) -> bool:
        # Always fetch current record from MDM, not from event payload
        record = job.event.after
        chunks = self._chunk_golden_record(record)
        vectors = []
        for i, chunk in enumerate(chunks):
            embedding = self.embed(chunk['text'])
            vectors.append({
                'id': job.chunk_id(i),
                'values': embedding,
                'metadata': {
                    'entity_id': record['entity_id'],
                    'entity_type': job.event.entity_type,
                    'chunk_index': i,
                    'content_hash': chunk['hash'],
                    'indexed_at': time.time(),
                },
            })
        self.vector.upsert(vectors)
        self.checker.record_sync(job.event.entity_id, len(vectors))
        return True

    def _chunk_golden_record(self, record: dict) -> list[dict]:
        text = f"{record.get('name', '')} {record.get('description', '')} "
        text += ' '.join(str(v) for v in record.get('attributes', {}).values())
        tokens = text.split()
        chunk_size = 200
        chunks = []
        for i in range(0, len(tokens), chunk_size):
            chunk_text = ' '.join(tokens[i:i + chunk_size])
            chunks.append({
                'text': chunk_text,
                'hash': hashlib.md5(chunk_text.encode()).hexdigest(),
            })
        return chunks

    def _handle_metadata_only(self, job: IndexSyncJob) -> bool:
        # Update vector metadata without re-embedding (cheaper)
        self.vector.update_metadata(
            filter={'entity_id': job.event.entity_id},
            metadata={'updated_at': time.time()},
        )
        return True
